(function(){
  if (window.html2pdf) return;
  function Worker(){ this._node = null; }
  Worker.prototype.set = function(){ return this; };
  Worker.prototype.from = function(node){ this._node = node; return this; };
  Worker.prototype.toPdf = function(){ return this; };
  Worker.prototype.outputPdf = function(){ return Promise.reject(new Error('html2pdf_stub_fallback')); };
  window.html2pdf = function(){ return new Worker(); };
})();
